18	pub fn is_builtin_excluded(path: &Path) -> bool {
19	    path.components().any(|c| {
20	        if let std::path::Component::Normal(name) = c {
21	            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
22	        } else {
23	            false
24	        }
25	    })
26	}
27	
28	fn git_check_ignore(path: &Path) -> Option<bool> {
29	    let abs = path.canonicalize().ok()?;
30	    let parent = abs.parent()?;
31	    let output = Command::new("git")
32	        .args([
33	            "-C",
34	            &parent.to_string_lossy(),
35	            "check-ignore",
36	            "--",
37	            &abs.to_string_lossy(),
38	        ])
39	        .output()
40	        .ok()?;
41	    Some(output.status.code() == Some(0))
42	}
43	
44	pub fn is_git_ignored(path: &Path) -> bool {
45	    git_check_ignore(path).unwrap_or(false)
46	}
